   // Check cache first
   const cacheKey = `numstat:${ref}`;
   const cached = diffCache.get(cacheKey);
   if (cached && Date.now() - cached.timestamp < CACHE_TTL_MS) {
     return cached.files;
   }

-  const { execSync } = require('child_process');
